def solve(n: int, edges: list[list[int]], label: str) -> int:
    from typing import List
    adj = [[] for _ in range(n)]
    for u, v in edges:
        adj[u].append(v)
        adj[v].append(u)

    max_len = 1

    def is_palindrome(s: str) -> bool:
        return s == s[::-1]

    def dfs(current: int, visited: int, path: str) -> None:
        nonlocal max_len
